{
  "email": "doctor@example.com",
  "password": "password123"
}

{
  "query": "{ __schema { queryType { name } } }"
}

{
  "query": "{ _service { sdl } }"
}

{
  "query": "mutation CreateAppointment($appointment: AppointmentInput!) { createAppointment(appointment: $appointment) { id status description start end minutesDuration comment participant { status actor { reference display } required } } }",
  "variables": {
    "appointment": {
      "status": "PROPOSED",
      "description": "Regular checkup appointment via API Gateway",
      "start": "2024-12-20T10:00:00Z",
      "end": "2024-12-20T10:30:00Z",
      "minutesDuration": 30,
      "comment": "Testing complete flow: API Gateway → Auth → Apollo → SchedulingService → Google Healthcare",
      "patientInstruction": "Please arrive 15 minutes early",
      "participant": [
        {
          "status": "ACCEPTED",
          "required": "REQUIRED",
          "actor": {
            "reference": "Patient/{{patient_id}}",
            "display": "Test Patient"
          }
        },
        {
          "status": "ACCEPTED",
          "required": "REQUIRED",
          "actor": {
            "reference": "Practitioner/{{practitioner_id}}",
            "display": "Dr. Test Practitioner"
          }
        }
      ]
    }
  }
}

{
  "query": "query GetAppointment($id: ID!) { appointment(id: $id) { id resourceType status description start end minutesDuration comment patientInstruction participant { status actor { reference display } required } } }",
  "variables": {
    "id": "{{appointment_id}}"
  }
}

{
  "query": "query SearchAppointments($patientId: String) { appointments(patientId: $patientId) { id status description start end participant { actor { reference display } } } }",
  "variables": {
    "patientId": "{{patient_id}}"
  }
}

{
  "query": "mutation UpdateAppointment($id: ID!, $appointment: AppointmentInput!) { updateAppointment(id: $id, appointment: $appointment) { id status description comment } }",
  "variables": {
    "id": "{{appointment_id}}",
    "appointment": {
      "status": "BOOKED",
      "description": "Updated appointment - confirmed booking",
      "comment": "Patient confirmed attendance via API Gateway flow"
    }
  }
}

{
  "query": "mutation CreateSchedule($schedule: ScheduleInput!) { createSchedule(schedule: $schedule) { id resourceType active actor { reference display } comment } }",
  "variables": {
    "schedule": {
      "active": true,
      "actor": [
        {
          "reference": "Practitioner/{{practitioner_id}}",
          "display": "Dr. Test Practitioner"
        }
      ],
      "comment": "Test schedule created via complete API Gateway flow"
    }
  }
}

{
  "query": "query GetSchedule($id: ID!) { schedule(id: $id) { id resourceType active actor { reference display } comment } }",
  "variables": {
    "id": "{{schedule_id}}"
  }
}

{
  "query": "query GetSchedulesByPractitioner($actorId: String, $active: Boolean) { schedules(actorId: $actorId, active: $active) { id resourceType active actor { reference display } planningHorizon { start end } comment serviceCategory { text coding { system code display } } serviceType { text coding { system code display } } specialty { text coding { system code display } } identifier { use system value } } }",
  "variables": {
    "actorId": "{{practitioner_id}}",
    "active": true
  }
}

{
  "query": "mutation CreateSlot($slot: SlotInput!) { createSlot(slot: $slot) { id resourceType status start end schedule { reference display } overbooked comment } }",
  "variables": {
    "slot": {
      "status": "FREE",
      "start": "2024-12-20T14:00:00Z",
      "end": "2024-12-20T14:30:00Z",
      "schedule": {
        "reference": "Schedule/{{schedule_id}}",
        "display": "Dr. Test Practitioner Schedule"
      },
      "overbooked": false,
      "comment": "Available slot created via API Gateway flow"
    }
  }
}

{
  "query": "query SearchSlots($status: SlotStatus) { slots(status: $status) { id status start end schedule { reference display } overbooked } }",
  "variables": {
    "status": "FREE"
  }
}

{
  "query": "query PatientAppointments($id: ID!) { patient(id: $id) { id name { family given } appointments { id status description start end participant { actor { reference display } } } } }",
  "variables": {
    "id": "{{patient_id}}"
  }
}

{
  "query": "query UserSchedulingData($id: ID!) { user(id: $id) { id firstName lastName appointments { id status description start end } schedules { id active actor { reference display } comment } } }",
  "variables": {
    "id": "{{practitioner_id}}"
  }
}

{
  "query": "query ComplexFederationQuery($patientId: ID!, $practitionerId: ID!) { patient(id: $patientId) { id name { family given } appointments { id status start end } } user(id: $practitionerId) { id firstName lastName schedules { id active } appointments { id status start end } } appointments { id status start end participant { actor { reference display } } } }",
  "variables": {
    "patientId": "{{patient_id}}",
    "practitionerId": "{{practitioner_id}}"
  }
}

{
  "query": "query VerifyAppointmentInGoogleHealthcare($id: ID!) { appointment(id: $id) { id resourceType status description start end participant { status actor { reference display } required } } }",
  "variables": {
    "id": "{{appointment_id}}"
  }
}

{
  "query": "query FHIRComplianceCheck($id: ID!) { appointment(id: $id) { id resourceType identifier { use system value } status serviceCategory { text coding { system code display } } serviceType { text coding { system code display } } appointmentType { text coding { system code display } } reasonCode { text coding { system code display } } priority description start end minutesDuration comment patientInstruction participant { type { text coding { system code display } } actor { reference display type } required status } } }",
  "variables": {
    "id": "{{appointment_id}}"
  }
}

{
  "query": "query TestAuth { appointments { id status } }"
}

{
  "query": "query GetNonExistentAppointment($id: ID!) { appointment(id: $id) { id status } }",
  "variables": {
    "id": "non-existent-appointment-id"
  }
}

{
  "query": "mutation CreateInvalidAppointment($appointment: AppointmentInput!) { createAppointment(appointment: $appointment) { id status } }",
  "variables": {
    "appointment": {
      "status": "INVALID_STATUS",
      "start": "invalid-date-format",
      "end": "invalid-date-format"
    }
  }
}

{
  "query": "query BulkQuery { appointments { id status start end participant { actor { reference } } } schedules { id active actor { reference } } slots { id status start end } }"
}

{
  "query": "query ComplexPerformanceTest { appointments { id status start end participant { actor { reference display } } } patients { id name { family given } appointments { id status } } users { id firstName lastName appointments { id status } schedules { id active } } }"
}
